import { useNavigate } from "react-router-dom";

export default function Navbar() {

  const nav = useNavigate();

  const logout = () => {
    localStorage.clear();
    nav("/");
  };

  return (
    <div style={styles.nav}>

      <h2 style={styles.logo}>
        DailyWorker
      </h2>

      <div style={styles.links}>

        <button style={styles.btn} onClick={() => nav("/")}>
          Home
        </button>

        <button style={styles.btn} onClick={() => nav("/customer")}>
          Customer
        </button>

        <button style={styles.btn} onClick={() => nav("/labour")}>
          Labour
        </button>

        <button style={styles.logout} onClick={logout}>
          Logout
        </button>

      </div>

    </div>
  );
}

const styles = {
  nav: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    background: "white",
    padding: "15px 40px",
    boxShadow: "0 2px 8px rgba(0,0,0,0.08)"
  },

  logo: {
    color: "#2563eb"
  },

  links: {
    display: "flex",
    gap: "15px"
  },

  btn: {
    background: "transparent",
    border: "none",
    cursor: "pointer"
  },

  logout: {
    background: "#ef4444",
    color: "white",
    border: "none",
    padding: "10px 15px",
    borderRadius: "8px"
  }
};
